var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"끝까지 멍청하기 짝이 없군......","JPN":"最後まで愚か極まりないな……","ENG":"You never learn, do you...","TWN":"直到最後都是這麼愚蠢……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"넌 날 흡수한 시점에서 이미 완전한 존재가 됐어.","JPN":"貴様は私を吸収した時点ですでに完全な存在となっていた。","ENG":"You already became complete when you absorbed me.","TWN":"從妳吸收我之後，就已經成為完整的存在了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그런데 그깟 대원들 때문에 영원한 고통을 감수하겠다고?","JPN":"それなのに、くだらん隊員たちのために永遠の苦しみを引き受けるだと？","ENG":"And yet you choose to endure eternal pain for those fools?","TWN":"而妳現在卻為了那些隊員，甘心承受永遠的痛苦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"내 원본이 이런 멍청이라니 그동안 집착했던 나까지 바보 같아지는군.","JPN":"オリジナルがここまで馬鹿だったとは、\\nこれまで拘ってきた私までもが愚かに思える。","ENG":"I can't believe my original would be so stupid. Now I feel dumb about obsessing over you so much.","TWN":"我的本體竟然如此愚蠢，搞得一直以來對妳如此執著的我，都像個笨蛋一樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"뭐, 됐어.","JPN":"まあ、いいだろう。","ENG":"Oh well.","TWN":"唉，算了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이렇게 된 거, 언제까지 고집을 부리나 네 안에서 지켜봐 주마.","JPN":"こうなったら、貴様がどこまで意地を通せるか、\\n貴様の内側から見届けてやる。","ENG":"I might as well as see how long you'll keep this up... as I lay inside you.","TWN":"既然妳決定這麼做，那我就看妳能堅持到什麼時候。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그거 알아, 류드밀라?","JPN":"ねぇ、知ってる？　リュドミラちゃん。","ENG":"You know what, Lyudmila?","TWN":"妳知道嗎，盧德米拉？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"실패작이었던 날 네가 구해 줬을 때, 뭐 이런 애가 다 있나 싶었어.","JPN":"失敗作だった私をリュドミラちゃんが助けてくれたとき、\\nおかしな子もいるものだと思ったわ。","ENG":"When you saved me, a failed product, I thought you were such a weirdo.","TWN":"當妳救了我這個失敗品時，我不禁懷疑世界上怎麼會有這樣的傢伙。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"관리국은 카운터가 중심인 조직인데, 넌 전대에 일반인부터 뽑아 왔으니까.","JPN":"管理局はカウンターが中心となる組織なのに、リュドミラちゃんは\\n戦隊に一般人を優先して起用したわよね。","ENG":"The Administration runs on Counters, but you recruited non-powered folks first into the division.","TWN":"管理局是一個制裁者為中心的組織，而妳卻從普通人開始選拔。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"기갑 병기가 중심이라 카운터는 별로 필요하지 않다고 해도, 그래서야 생환율이 떨어질 수밖에 없잖아.","JPN":"機甲兵器が主戦力だからカウンターはそんなに要らないとは\\nいっても、やっぱり高い生還率は見込めなくなっちゃうでしょ？","ENG":"Maybe we didn't need that many Counters with all the armored vehicles, but that would still lower our chance of survival.","TWN":"儘管以機械兵器為主的戰隊不是很需要制裁者，因為那樣會降低生存率。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"처음에는 쓰고 버리기 편한 부하들만 찾는 바보인 줄 알았는데......","JPN":"最初は使い捨てにしやすい部下を募るバカなのかと思ったけど……","ENG":"So at first, I thought you were just trying to stock up on easily expendable troops...","TWN":"所以一開始，我以為妳是個在利用完隊員後，就會把隊員丟棄的渾蛋……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"기록을 봤더니 우리 전대의 생환율이 관리국 전체 1위더라고.","JPN":"記録を見てみたら、うちの戦隊の生還率は管理局全体で\\n1位だったの。","ENG":"But when I checked out the database, our division had the highest rate of survival in the entire Administration.","TWN":"但是我看記錄後才發現，我們戰隊的生存率是管理局第一。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"심지어 그 콧대 높은 펜릴 전대보다 위였다니까?","JPN":"あのプライドの塊のフェンリル戦隊よりも上だったのよ？","ENG":"We even beat those revered guys from Fenrir!","TWN":"甚至比那個趾高氣昂的芬里爾戰隊還高。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그제서야 널 이해하게 됐어.","JPN":"それでようやく、アナタのことが理解できたわ。","ENG":"That's when I finally began to understand you.","TWN":"我那時才終於了解了妳。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"바보가 아니라, 아무도 신경 쓰지 않는 평범한 사람들이 죽거나 다치지 않게 최선을 다해 온 고집쟁이라는 걸.","JPN":"アナタはバカなんかじゃなかった。\\n誰も気にも留めない平凡なみんなを死や負傷から守りたくて、\\nそのために最善を尽くす意地っ張りだったのよね。","ENG":"You're not a fool. You're just a stubborn person who has been fighting to make sure ordinary folks that no one cares about don't have to die or get hurt.","TWN":"妳不是渾蛋，而是一個盡全力保護那些沒有人在乎的普通人，不讓他們死掉，或是受傷的死腦筋。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"남은 대원들도, 그리고 여기까지 오지 못한 대원들도......","JPN":"残された隊員たちも、そして、ここまで来られなかった隊員たちも……","ENG":"So all of us who are still here... and those that fell before us...","TWN":"剩下的隊員，還有沒能一起走到現在的隊員們……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"모두 네게 고마워하고 있을 거야.","JPN":"みんながアナタに感謝してると思うわ。","ENG":"I'm sure they're all grateful to you.","TWN":"也都對妳心存感激。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그러니까...... 이제 눈을 뜰 시간이야.","JPN":"だから……もうお目覚めの時間よ。","ENG":"So... you should wake up now.","TWN":"所以……快睜開眼睛吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"커헉! 크으으......!","JPN":"ガハッ！　くうぅッ……！","ENG":"Hngh! Ugh!","TWN":"咳！呃呃呃！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_THUD"},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"벌써 눈을 떴나? 예상보다는 좀 빠르군.","JPN":"もう目が覚めたか？　予想より少し早かったな。","ENG":"Awake already? That was a bit quicker than I thought.","TWN":"這麼快就醒了？比我預想得還要快呢。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"여, 여긴 어디......","JPN":"こ、ここは、どこ……","ENG":"W-where am I?","TWN":"這、這裡是……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아윽......!","JPN":"あうっ……！","ENG":"Ugh!","TWN":"啊呃……！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그냥 누워 있게. 침식통이 심할 테니까.","JPN":"無理をせず横になりたまえ。侵食痛が激しいだろうからな。","ENG":"Just lie down. The Corruption-ache must be pretty bad right now.","TWN":"妳還是躺著吧，侵蝕痛很嚴重的。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 진통제를 놔 주지. 아주 비싼 고순도 이터니움으로 만든 거니까 당분간 괜찮을 거야.","JPN":"今、鎮痛剤を打ってやる。超高額な高純度エタニウムで\\n作ったものだから、しばらくは大丈夫だろう。","ENG":"I'll give you something to ease the pain. This is made with very expensive, high-purity Eternium. This should make you a bit more comfortable for a while.","TWN":"我給妳打鎮定劑吧，是用非常昂貴的高純度永恆之金製作的，應該可以暫時緩解痛苦。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"여긴...... 여긴 어딥니까......?","JPN":"ここは……ここはどこですか……？","ENG":"Where... am I?","TWN":"這裡……這裡是什麼地方……？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"현실세계라네. 시술을 마치고 자네가 잠들어 있는 동안 귀환했지.","JPN":"現実世界だ。施術を終え、君が眠っている間に帰還した。","ENG":"Normalside. We came back after the procedure; you were asleep.","TWN":"是現實世界。手術結束後，我們在妳陷入沉睡時回來了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"방주의 클리파 봉인 재조정도 끝났으니, 도플갱어들이 예전보다 자주 나타나는 걸 제외하면 우리 일도 잘 마무리 된 셈이야.","JPN":"箱舟のクリファ次元封印の再調整も済ませたので、ドッペルゲンガーたちが\\n前より頻繁に出没するだろうことを除けば、\\n我々の用事も上手く解決できたわけだ。","ENG":"We've finished recalibrating the Qlipha seal on the Ark too, so it all worked out for the best... other than the fact that the Doppelgangers are showing up more often than before.","TWN":"方舟的逆卡巴拉封印也重新調整好了，除了二重身會比以前更頻繁地出現之外，我們的事情也算圓滿完成了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들...... 대원들은 어떻게......","JPN":"隊員たち……隊員たちはどうなって……","ENG":"My troops... What happened to them?","TWN":"隊員們……隊員們怎麼樣了……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 말게. 다들 무사하니까.","JPN":"安心しろ。みんな無事だ。","ENG":"Don't worry. They're all safe.","TWN":"放心，他們都沒事。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금은 모두 자네의 그림자 세계에 들어가 있어.","JPN":"今はみんな、君のシャドウサイドの中に入っている。","ENG":"For now, they're all in your Shadow World.","TWN":"他們現在在妳的暗影世界裡。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그림자 세계.....? 그건 뭡니까?","JPN":"シャドウサイド……？　それは何なのですか？","ENG":"Shadow World? What's that?","TWN":"暗影世界……？那是什麼？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"본체가 도플갱어를 역으로 흡수한 탓에, 자네는 예상보다 더 높은 고위 침식체가 되었더군.","JPN":"本体がドッペルゲンガーを逆に吸収したせいで、\\n君は予想よりも遥かに高位の侵食体となっていたからな。","ENG":"Because the original absorbed the Doppelganger, you ended up becoming a much higher tier C.O. than I imagined.","TWN":"由於本體反過來吸收了二重身，妳變成了超乎想像的高等侵蝕體。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"게다가 시술의 영향으로 흥미로운 능력이 많이 생겼어.","JPN":"しかも、施術の影響で興味深い能力も数多く発現している。","ENG":"And you got a bunch of new intriguing abilities thanks to the procedure.","TWN":"而且因為手術的影響，妳獲得了很多有趣的能力。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그림자 세계는 자네가 지닌 일종의 아공간이네.","JPN":"シャドウサイドは君が持っている一種の亜空間だ。","ENG":"The Shadow World is a sort of an alternate dimension within you.","TWN":"暗影世界是妳擁有的一種亞空間。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네에게 침식 전이를 한 대상은 그 안에 머물다가 자네가 원하면 언제든 밖으로 나올 수 있지.","JPN":"君に侵食転移した対象はその中に留まり、\\n君が望めばいつでも外に出られる。","ENG":"The folks who had their Corruption transferred to you can reside in your Shadow World and come back out whenever you wish.","TWN":"侵蝕轉移給妳的對象會留在那個世界，妳需要的時候可以隨時叫出來。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대원들도 당분간 그곳에 머물겠다더군.","JPN":"隊員たちもしばらくはそこに留まりたいのだそうだ。","ENG":"They said they'd stay in there for the time being.","TWN":"妳的隊員也說想暫時留在那個世界裡。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식이 진행됐던 사람들에게 현실 공기는 자극이 심하거든.","JPN":"侵食が進んだことのある人間にとって、\\n現実世界の空気は刺激が強いからな。","ENG":"The Normalside's atmosphere can feel pretty aggravating for those who have been corrupted.","TWN":"對於被侵蝕的人來說，現實世界的空氣帶來刺激實在太強了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"축하할 일인지는 모르겠지만......","JPN":"祝っていいことかわからないが……","ENG":"Although I'm not sure if it would be appropriate to congratulate you for this...","TWN":"雖然不知道是不是值得慶賀的事情……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런 능력이라면 훌륭한 데몬 타입 침식체라고 해도 손색이 없겠어.","JPN":"これだけの能力を備えているなら、歴としたデーモンタイプ侵食体を\\n名乗っても遜色はないだろう。","ENG":"But you'll make a fine Demon-type C.O. like this.","TWN":"不過有了這個能力，說妳是個優秀的惡魔型侵蝕體也不為過。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_DEMON_NULL","text":{"KOREA":"그렇......군요.","JPN":"そう……ですか。","ENG":"I... see...","TWN":"原來……如此"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 이제 어떻게 할 텐가?","JPN":"で、これからどうするつもりなのかね？","ENG":"So, what are you going to do now?","TWN":"那麼，接下來妳有什麼打算？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"구 관리국은 사라졌으니 자네는 이제 자유일세.","JPN":"旧管理局は消滅している。君はもう自由だ。","ENG":"You don't have any contractual obligations, since the Old Administration is no more.","TWN":"舊管理局已消失，妳現在自由了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"평범하게 살아도 좋고, 용병이 되길 원한다면 이수연 부사장이 도와 줄 거야.","JPN":"平凡な暮らしを望むならそれもよし。傭兵になりたいのなら、\\nわが社の副社長カナミ・キズナを頼るといい。","ENG":"You can lead an ordinary life if you wish, or if you want to become a mercenary, Sooyeon should be able to help you out.","TWN":"妳可以過普通人的日子，想當傭兵的話，李秀妍副總也會幫妳。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_DEMON_NULL","text":{"KOREA":"......아뇨. 괜찮습니다.","JPN":"……いいえ。大丈夫です。","ENG":"No. It's okay.","TWN":"……不，沒關係。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_DEMON_NULL","text":{"KOREA":"전 예전에도, 그리고 지금도 메이즈 전대의 전대장입니다.","JPN":"私はかつても、そして今も、メイズ戦隊の戦隊長です。","ENG":"I still am the Commander of Maze Division, as I always have been.","TWN":"不論是以前，還是現在，我都是梅茲戰隊的隊長。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_DEMON_NULL","text":{"KOREA":"그러니 허락해 주신다면, 앞으로도 곁에서 관리자님을 돕고 싶습니다.","JPN":"ですので、もしお許しいただけるならこれからも管理者様のお傍で\\n補佐を務めさせていただきたいと思います。","ENG":"So with your permission, I'd like to continue helping you by your side.","TWN":"所以如果您允許，之後我想幫助管理者大人。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런가......","JPN":"そうか……","ENG":"I see...","TWN":"是嗎……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 앞으로도 잘 부탁하지.","JPN":"ならば、これからもよろしく頼む。","ENG":"Well then, I look forward to working with you.","TWN":"那以後就請多多指教了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시작부터 미안하지만 할 일이 아주 많을 거야.","JPN":"初っ端から悪いが、やるべきことは山積みだぞ。","ENG":"I'm sorry to say this, but you're going to be very busy right from the start.","TWN":"一開始就這麼說雖然有點抱歉，但會有很多的事情需要妳幫忙。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_DEMON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_DEMON_NULL","text":{"KOREA":"바라던 바입니다.","JPN":"望むところです。","ENG":"I wouldn't have it any other way.","TWN":"求之不得。"},"stage":{"bg":"SS_ADMIN_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어떻게 됐죠?","JPN":"どうなりました？","ENG":"How did it go?","TWN":"她怎麼樣了？"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무사히 깨어났네. 지금은 쉬고 있어.","JPN":"無事に目覚めたよ。今は休んでいる。","ENG":"She's awake and well. She's resting for now.","TWN":"平安地醒了過來，現在正在休息。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......다행이군요.","JPN":"……よかったです。","ENG":"That’s good.","TWN":"……真是太好了。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"앞으로는 어떻게 하겠다고 하던가요?","JPN":"これからどうすると言っていました？","ENG":"And what does she want to do from now on?","TWN":"她有說接下來要做什麼嗎？"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 곁에서 일을 돕고 싶다더군. 마침 믿을 만한 일손이 필요하던 차였는데 잘 됐어.","JPN":"私の傍で仕事を手伝いたいそうだ。\\nちょうど信頼できる人手が欲しかったところなので好都合だった。","ENG":"She says she wants to help me. Perfect timing too. I was just in need of someone reliable.","TWN":"她說要留在我身邊幫我，正好我這邊需要一個幫手，真是太好了。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"회복되면 더 늦기 전에 다른 방주들의 봉인도 재조정을 하러 가야겠지.","JPN":"体調が回復次第、手遅れになる前に他の箱舟の封印も\\n再調整しに行かないとな。","ENG":"As soon as she recovers, I'll have to take her to help me recalibrate the other Arks' seals before it's too late.","TWN":"等她恢復後，趁事情為時已晚之前，我得去重新調整其他方舟的封印才行。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇군요......","JPN":"そうですか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"수심이 깊은 얼굴이군.","JPN":"顔に憂いが見て取れるぞ。","ENG":"You seem troubled.","TWN":"妳看起來很凝重。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"친구가 걱정되나?","JPN":"友人の身が心配か？","ENG":"Are you worried for your friend?","TWN":"是在擔心妳的朋友嗎？"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......아니오.","JPN":"……いいえ。","ENG":"No.","TWN":"……不是。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전 류드밀라처럼 정이 많지 않아서요.","JPN":"私はリュドミラのように情の深い性格ではありません。","ENG":"I'm not as caring as Lyudmila is.","TWN":"我不像盧德米拉那樣多情。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제 일이 아니면 가급적 신경 쓰지 않겠다는 주의입니다.","JPN":"自分のことでないならあまり気に留めない主義です。","ENG":"I try not to get involved if it's none of my business.","TWN":"除非是我的事情，不然我就不會去關心。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이래서 나이가 들면 순수함이 사라진다고 하는 거로군.","JPN":"歳を取ると純粋さが失われるとはよくいったものだな。","ENG":"So this is why they say people lose their innocence as they age.","TWN":"怪不得長大後會失去兒時的純真。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어렸을 땐 좀 더 귀여운 성격이었던 것 같은데 말이지.","JPN":"昔の君はもう少し可愛げのある性格だったと思うが。","ENG":"You seemed a bit more lovable when you were younger.","TWN":"妳小時候明明很討人喜歡的。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>속보입니다. 방금 전, 관리국은 일부 고심도 좌표에서 그림자 전당이라는 특이 현상이 관측되었다고 밝혔습니다.</color>","JPN":"<color=#ffd34c>速報です。先ほど管理局は一部の高深度座標にて、影の殿堂と\\n称される特異現象を観測したと発表しました。</color>","ENG":"<color=#ffd34c>This just in. The Administration just announced that they observed the anomalies known as Shadow Palaces in certain deep coordinates.</color>","TWN":"<color=#ffd34c>緊急速報，不久前，管理局在部分高深度座標觀測到了暗影殿堂現象。</color>"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_TECH_09"},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>또한 해당 지역은 다수의 도플갱어가 출몰하므로, 안전 보장 차원에서 각 태스크포스 컴퍼니에 적극적인 공략을 요청한 상태라고 합니다.</color>","JPN":"<color=#ffd34c>また、該当地域にはドッペルゲンガーが多数出没しており、安全保障の観点から\\n各タスクフォースカンパニーに積極的な攻略を要請しているとのことです。</color>","ENG":"<color=#ffd34c>The officials also said that due to the frequent appearance of multiple Doppelgangers in the area, they've asked for the support from TASKFORCE Companies to ensure public safety.</color>","TWN":"<color=#ffd34c>並且由於該地區出現大量二重身，出於安全考量，已請求各特遣勢力公司展開積極攻略。</color>"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국은 공략 장려를 위해 이례적으로 높은 공략 보상을 책정하였으며, 해당 지역에서 획득한 부산물에 대해서도 높은 비율의 분배를 약속......</color>","JPN":"<color=#ffd34c>管理局は攻略奨励のため、異例の高額な攻略報酬を掲げており、\\n該当地域で獲得した副産物に関しても高い比率での\\n振り分けを約束……</color>","ENG":"<color=#ffd34c>The Administration has offered unprecedented rewards for clearing these Palaces, and a high ratio of the spoils to be claimed in the area...</color>","TWN":"<color=#ffd34c>為了鼓勵攻略，管理局破例開出了高昂的攻略獎勵，並保證在該區域獲得的副產品，會以極高的比率分配……</color>"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님......","JPN":"社長……","ENG":"Boss...","TWN":"老闆……"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"왜 그러나?","JPN":"どうした？","ENG":"What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이번 세계가 실패한다면...... 당신은 또 다음 세계로 떠나는 건가요?","JPN":"今回の世界が失敗したら……\\nあなたは、また次の世界へ発たれるのですか？","ENG":"If this world fails too, will you be leaving to the next world again?","TWN":"如果這個世界失敗的話……你又會前往下一個世界嗎？"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그랬으면 좋겠지만...... 이번에는 방주의 에너지를 모두 봉인에 써 버려서 말이야.","JPN":"それができれば苦労はしないが……今回は箱舟のエネルギーを\\nすべて封印に費やしたからな。","ENG":"I wish I could... But this time, I spent all of the Arks' energy on sealing the portals.","TWN":"我也希望能那樣……但這次我把方舟的能量全部用在封印上了。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실패한다면 다음은 없을 것 같군.","JPN":"失敗すれば、いよいよ次はなさそうだ。","ENG":"I don't think there will be a next time if I fail again.","TWN":"如果失敗，就不會有下一次了。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그렇군요.","JPN":"……そうですか。","ENG":"I see.","TWN":"……原來如此。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님......","JPN":"社長……","ENG":"Boss...","TWN":"老闆……"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"또 왜 그러나?","JPN":"まだ何かあるのか？","ENG":"What now?","TWN":"又怎麼了？"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우리가...... 이길 수 있을까요?","JPN":"私たちは……勝てるのですか？","ENG":"Do you think... we can win?","TWN":"我們……會贏嗎？"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니...... 살아남을 수 있을까요?","JPN":"いえ……生き延びることができるでしょうか？","ENG":"Or rather... survive?","TWN":"不……我們能活下來嗎？"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......물론.","JPN":"……無論だ。","ENG":"Of course.","TWN":"……當然！"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 그렇게 만들 생각이네.","JPN":"私がその未来を作るつもりだ。","ENG":"I'll see to it personally.","TWN":"我就是這麼打算的。"},"stage":{"bg":"SS_ADMIN_04","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};